import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Button,
  Checkbox,
  Input,
  Modal,
  SearchTextInput,
  dispatchAppToast,
  LeaveConfirmModal,
  LinListFilterField,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import { systemService } from '../../../services/system/systemService';
import type { PostingReasonRuleDto } from '../../../services/master/models';
import type { VoucherRegistryDto } from '../../../services/system/voucherRegistryModels';
import { normalizeCode } from '../../../utils/codeField';
import {
  joinAllowedVoucherTypeCodes,
  parseAllowedVoucherTypeCodes,
} from '../../../utils/postingReasonVoucherAccess';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { useCatalogMasterListRowMenu } from '../../../hooks/useCatalogMasterListRowMenu';
import {
  CatalogCompanyField,
  useCatalogListPaging,
  useCatalogTableBusy,
  SharedCatalogFormActions,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogListMasterLinPageLayout,
  CatalogFormHistorySlot,
  CatalogListHeaderFilters,
  CatalogRowActionMenu,
} from '../../../components/catalog';
import {
  CatalogListGridFromSchema,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
  proposalEditableFields,
  toProposalFieldDefs,
} from '../../../components/catalog/catalogUiSchema';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-dinh-khoan-nghiep-vu';
const CATALOG_KIND = 'posting-reason-rules';

type FormErrors = Partial<Record<'code' | 'name' | 'reasonGroup' | 'documentType' | 'debitAccountCode' | 'creditAccountCode', string>>;

const DinhKhoanNghiepVuPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<PostingReasonRuleDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<PostingReasonRuleDto | null>(null);
  const [form, setForm] = useState<Partial<PostingReasonRuleDto>>({});
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);
  const [voucherRegistry, setVoucherRegistry] = useState<VoucherRegistryDto[]>([]);

  const allowedVoucherCodes = useMemo(
    () => parseAllowedVoucherTypeCodes(form.allowedVoucherTypeCodes),
    [form.allowedVoucherTypeCodes],
  );

  useEffect(() => {
    if (!modalOpen) return;
    let cancelled = false;
    systemService.getVoucherRegistry()
      .then(rows => {
        if (!cancelled) setVoucherRegistry(rows.filter(r => r.isActive));
      })
      .catch(() => {
        if (!cancelled) setVoucherRegistry([]);
      });
    return () => { cancelled = true; };
  }, [modalOpen]);

  const toggleAllowedVoucher = useCallback((voucherTypeCode: string, checked: boolean) => {
    markDirty();
    const next = new Set(allowedVoucherCodes);
    if (checked) next.add(voucherTypeCode);
    else next.delete(voucherTypeCode);
    setForm(f => ({
      ...f,
      allowedVoucherTypeCodes: joinAllowedVoucherTypeCodes([...next]),
    }));
  }, [allowedVoucherCodes, markDirty]);

  const { schema, reload: reloadSchema } = useCatalogUiSchema(CATALOG_KIND);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);
  const proposalFieldDefs = useMemo(
    () => toProposalFieldDefs(proposalEditableFields(schema)),
    [schema],
  );

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const totalCount = items.length;
  const pagedItems = useMemo(() => {
    const start = (page - 1) * pageSize;
    return items.slice(start, start + pageSize);
  }, [items, page, pageSize]);

  const selection = useCatalogListSelection({
    rows: pagedItems,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService.getPostingReasonRules({ search: search || undefined })
        .then(data => { if (!cancelled) setItems(data); })
        .catch(err => {
          if (!cancelled) dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải quy tắc định khoản', type: 'error' });
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã quy tắc';
    if (!form.name?.trim()) next.name = 'Nhập tên nghiệp vụ';
    if (!form.reasonGroup?.trim()) next.reasonGroup = 'Nhập nhóm nghiệp vụ';
    if (!form.documentType?.trim()) next.documentType = 'Nhập loại chứng từ';
    if (!form.debitAccountCode?.trim()) next.debitAccountCode = 'Nhập TK Nợ';
    if (!form.creditAccountCode?.trim()) next.creditAccountCode = 'Nhập TK Có';
    return next;
  };

  const closeFormModal = () => {
    setModalOpen(false);
    markClean();
  };

  const openAdd = () => {
    setViewOnlyShared(false);
    setEditing(null);
    setForm({});
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openView = useCallback((row: PostingReasonRuleDto) => {
    setViewOnlyShared(true);
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [markClean]);

  const openEditImpl = useCallback((row: PostingReasonRuleDto) => {
    setViewOnlyShared(false);
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [markClean]);

  const rowMenu = useCatalogMasterListRowMenu({
    testIdPrefix: TEST_ID,
    catalogKind: CATALOG_KIND,
    selection,
    openEdit: openEditImpl,
    openView,
  });

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) await masterService.updatePostingReasonRule(editing.id, form);
      else await masterService.createPostingReasonRule(form);
      dispatchAppToast(dispatch, { message: editing ? 'Cập nhật quy tắc định khoản thành công' : 'Tạo quy tắc định khoản thành công', type: 'success' });
      markClean();
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? items.filter(r => !isSharedCatalogReadOnly(r)).map(r => r.id)
        : [...selection.selectedIds].filter(id => {
            const row = pagedItems.find(r => r.id === id) ?? items.find(r => r.id === id);
            return row && !isSharedCatalogReadOnly(row);
          });
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.id === id)!;
        return masterService.updatePostingReasonRule(id, { ...row, isActive: false });
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} quy tắc định khoản`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deletePostingReasonRule(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} quy tắc định khoản`, type: 'success' });
    }
    refresh();
  };

  const filterBar = (
    <CatalogListHeaderFilters testIdPrefix={TEST_ID} filterMaxWidthPx={1000}>
      <LinListFilterField testId={`${TEST_ID}-field-search`}>
        <SearchTextInput
          label="Tìm kiếm"
          placeholder="Tìm mã, tên..."
          value={searchDraft}
          onChange={setSearchDraft}
          onSearch={handleSearch}
          testId={`${TEST_ID}-search-text`}
        />
      </LinListFilterField>
    </CatalogListHeaderFilters>
  );

  return (
    <>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={pagedItems.filter(r => !isSharedCatalogReadOnly(r))}
        onAdd={openAdd}
        onEdit={rowMenu.openEditWithPerm}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        proposalFieldDefs={proposalFieldDefs.length > 0 ? proposalFieldDefs : undefined}
        toolbarBridgeRef={rowMenu.toolbarBridgeRef}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setPage(p); selection.clearSelection(); }}
        onPageSizeChange={setPageSize}
        showTableLoading={showTableLoading}
        header={{ title: 'Quy tắc định khoản', titleIconClass: 'fas fa-balance-scale' }}
        listTitle="Danh sách quy tắc định khoản"
        listRowMenuHelp
        filtersTestId={`${TEST_ID}-filters`}
        filterMaxWidthPx={1000}
        filters={filterBar}
        schemaEditorModal={(
          <CatalogUiSchemaEditorModal
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            isOpen={schemaEditorOpen}
            onClose={() => setSchemaEditorOpen(false)}
            onSaved={() => {
              reloadSchema();
              refresh();
            }}
          />
        )}
        extraModals={(
          <>
            <CatalogRowActionMenu {...rowMenu.rowActionMenuProps} />
            <LeaveConfirmModal {...leaveConfirmModalProps} />
          </>
        )}
      >
        {pagedItems.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy mẫu phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : listColumns.length > 0 ? (
          <CatalogListGridFromSchema
            testIdPrefix={TEST_ID}
            rows={pagedItems}
            page={page}
            pageSize={pageSize}
            columns={listColumns}
            schema={schema}
            selection={selection}
            getRowId={r => r.id}
            isRowSelectable={r => !isSharedCatalogReadOnly(r)}
            {...rowMenu.gridRowMenuProps}
          />
        ) : null}
      </CatalogListMasterLinPageLayout>

      <Modal
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={viewOnlyShared ? 'Xem quy tắc định khoản dùng chung' : editing ? 'Sửa quy tắc định khoản' : 'Thêm quy tắc định khoản'}
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-reasonGroup`}>
                <label className={styles.label}>Nhóm *</label>
                <Input
                  value={form.reasonGroup ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.reasonGroup}
                  placeholder="BAOCO, PT, CCH..."
                  onChange={e => {
                    markDirty();
                    clearFieldError('reasonGroup');
                    setForm(f => ({ ...f, reasonGroup: e.target.value }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-documentType`}>
                <label className={styles.label}>Loại CT FM *</label>
                <Input
                  value={form.documentType ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.documentType}
                  placeholder="T, BC, C..."
                  onChange={e => {
                    markDirty();
                    clearFieldError('documentType');
                    setForm(f => ({ ...f, documentType: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-allowedVoucherTypeCodes`}>
              <label className={styles.label}>Chứng từ ERP được phép</label>
              <p style={{ margin: '0 0 8px', fontSize: '0.875rem', opacity: 0.85 }}>
                Không chọn = áp dụng mọi loại chứng từ. Chọn để giới hạn lookup trên form PT/PC.
              </p>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                {voucherRegistry.map(v => (
                  <Checkbox
                    key={v.voucherTypeCode}
                    label={`${v.name} (${v.voucherTypeCode})`}
                    checked={allowedVoucherCodes.includes(v.voucherTypeCode)}
                    disabled={viewOnlyShared}
                    onChange={e => toggleAllowedVoucher(v.voucherTypeCode, e.target.checked)}
                    data-testid={`${TEST_ID}-voucher-${v.voucherTypeCode}`}
                  />
                ))}
              </div>
            </div>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-debitAccountCode`}>
                <label className={styles.label}>TK Nợ FM *</label>
                <Input
                  value={form.debitAccountCode ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.debitAccountCode}
                  placeholder="911..."
                  onChange={e => {
                    markDirty();
                    clearFieldError('debitAccountCode');
                    setForm(f => ({ ...f, debitAccountCode: e.target.value }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-creditAccountCode`}>
                <label className={styles.label}>TK Có FM *</label>
                <Input
                  value={form.creditAccountCode ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.creditAccountCode}
                  placeholder="421..."
                  onChange={e => {
                    markDirty();
                    clearFieldError('creditAccountCode');
                    setForm(f => ({ ...f, creditAccountCode: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-erpDebitAccountCode`}>
                <label className={styles.label}>TK Nợ ERP</label>
                <Input
                  value={form.erpDebitAccountCode ?? ''}
                  disabled={viewOnlyShared}
                  placeholder="5111, 1131..."
                  onChange={e => {
                    markDirty();
                    setForm(f => ({ ...f, erpDebitAccountCode: e.target.value }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-erpCreditAccountCode`}>
                <label className={styles.label}>TK Có ERP</label>
                <Input
                  value={form.erpCreditAccountCode ?? ''}
                  disabled={viewOnlyShared}
                  placeholder="5111, 1311..."
                  onChange={e => {
                    markDirty();
                    setForm(f => ({ ...f, erpCreditAccountCode: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-expenseItemCode`}>
              <label className={styles.label}>Khoản chi phí</label>
              <Input
                value={form.expenseItemCode ?? ''}
                disabled={viewOnlyShared}
                placeholder="CP2019 (optional)"
                onChange={e => {
                  markDirty();
                  setForm(f => ({ ...f, expenseItemCode: e.target.value }));
                }}
              />
            </div>
          </div>
          <CatalogCompanyField
            testIdPrefix={TEST_ID}
            companyName={editing?.companyName ?? sessionCompanyName}
          />
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            row={editing}
            currentValues={{
              name: form.name,
              debitAccountCode: form.debitAccountCode,
              creditAccountCode: form.creditAccountCode,
            }}
            {...sharedForm}
          />
          <div className={styles.modalActions}>
            <CatalogFormHistorySlot
              testIdPrefix={TEST_ID}
              catalogKind={CATALOG_KIND}
              editing={editing ? { id: editing.id, code: editing.code } : null}
            />
            <Button variant="secondary" onClick={closeFormModal}>Hủy</Button>
            <Button
              variant="primary"
              onClick={handleSave}
              disabled={saving || viewOnlyShared}
              data-testid={`${TEST_ID}-save-btn`}
            >
              {saving ? 'Đang lưu...' : 'Lưu'}
            </Button>
          </div>
        </div>
      </Modal>
    </>
  );
};

export default DinhKhoanNghiepVuPage;
