/** VoucherRegistry.VoucherTypeCode allow-list for posting reason rules. */

export function parseAllowedVoucherTypeCodes(raw?: string | null): string[] {
  if (!raw?.trim()) return [];
  return [...new Set(raw.split(',').map(x => x.trim()).filter(Boolean))];
}

export function joinAllowedVoucherTypeCodes(codes: readonly string[]): string | undefined {
  const normalized = [...new Set(codes.map(x => x.trim()).filter(Boolean))].sort();
  return normalized.length > 0 ? normalized.join(',') : undefined;
}

export function formatAllowedVoucherLabel(raw?: string | null): string {
  const codes = parseAllowedVoucherTypeCodes(raw);
  return codes.length > 0 ? codes.join(', ') : 'Tất cả chứng từ';
}

export const POSTING_REASON_VOUCHER_DEFAULTS = {
  cashReceipt: 'phieu-thu',
  cashPayment: 'phieu-chi',
} as const;
